// PodsHealthStatus is the resolver for the podsHealthStatus field.
func (r *k8sWorkloadResolver) PodsHealthStatus(ctx context.Context, obj *model.K8sWorkload) (*model.DesiredConditionStatus, error) {
	l := loaders.For(ctx)
	pods, err := l.GetWorkloadPods(ctx, *obj.ID)
	if err != nil {
		return nil, err
	}

	// aggregate the health status of all containers in all pods
	containersHealthConditions := make([]*model.DesiredConditionStatus, 0, len(pods))
	for _, pod := range pods {
		for _, container := range pod.Containers {
			healthStatus := status.CalculatePodContainerK8sHealthStatus(&container)
			containersHealthConditions = append(containersHealthConditions, healthStatus)
		}
	}

	aggregatePodHealthStatus := status.AggregateConditionsBySeverity(containersHealthConditions)
	if aggregatePodHealthStatus == nil {
		reasonStr := string(status.PodContainerK8sHealthReasonUnknown)
		return &model.DesiredConditionStatus{
			Name:       status.PodHealthStatus,
			Status:     model.DesiredStateProgressError,
			ReasonEnum: &reasonStr,
			Message:    "not able to determine health status for containers in pods",
		}, nil
	}
	if aggregatePodHealthStatus.ReasonEnum != nil {
		if *aggregatePodHealthStatus.ReasonEnum == string(status.PodContainerK8sHealthReasonHealthy) {
			aggregatePodHealthStatus.Message = "all containers in all pods are reported healthy in kubernetes"
		} else if *aggregatePodHealthStatus.ReasonEnum == string(status.PodContainerK8sHealthReasonNotStarted) {
			aggregatePodHealthStatus.Message = "some containers in this workload's pods are not started yet"
		} else if *aggregatePodHealthStatus.ReasonEnum == string(status.PodContainerK8sHealthReasonNotReady) {
			aggregatePodHealthStatus.Message = "some containers in this workload's pods are not ready yet"
		} else if *aggregatePodHealthStatus.ReasonEnum == string(status.PodContainerK8sHealthReasonCrashLoopBackOff) {
			aggregatePodHealthStatus.Message = "some containers in this workload's pods are in crash loop back off"
		}
	}
	return aggregatePodHealthStatus, nil
}

// PodsOdigosHealthStatus is the resolver for the podsOdigosHealthStatus field.
func (r *k8sWorkloadResolver) PodsOdigosHealthStatus(ctx context.Context, obj *model.K8sWorkload) (*model.DesiredConditionStatus, error) {
	l := loaders.For(ctx)
	pods, err := l.GetWorkloadPods(ctx, *obj.ID)
	if err != nil {
		return nil, err
	}

	ic, err := l.GetInstrumentationConfig(ctx, *obj.ID)
	if err != nil {
		return nil, err
	}

	if len(pods) == 0 {
		reasonStr := string(status.PodHealthOdigosStatusReasonNoPods)
		return &model.DesiredConditionStatus{
			Name:       status.PodHealthOdigosStatus,
			Status:     model.DesiredStateProgressUnknown,
			ReasonEnum: &reasonStr,
			Message:    "no pods for this workload",
		}, nil
	}

	// aggregate the health status of all containers in all pods
	containersHealthConditions := make([]*model.DesiredConditionStatus, 0, len(pods))
	for _, pod := range pods {
		containersOdigosHealthConditions := make([]*model.DesiredConditionStatus, 0, len(pod.Containers))
		for _, container := range pod.Containers {
			containerConfig := getContainerConfigByName(ic, container.ContainerName)
			iis, err := l.GetInstrumentationInstancesForContainer(ctx, loaders.PodContainerId{
				Namespace:     pod.PodNamespace,
				PodName:       pod.PodName,
				ContainerName: container.ContainerName,
			})
			if err != nil {
				return nil, err
			}
			healthStatus := status.CalculatePodContainerHealthOdigosStatus(&container, containerConfig, iis)
			if healthStatus != nil {
				containersOdigosHealthConditions = append(containersOdigosHealthConditions, healthStatus)
			}
		}
		healthStatus := status.CalculatePodHealthOdigosStatus(&pod, containersOdigosHealthConditions)
		if healthStatus != nil {
			containersHealthConditions = append(containersHealthConditions, healthStatus)
		}
	}

	agg := status.AggregateConditionsBySeverity(containersHealthConditions)
	return status.MostSeverPodStatusToAggregated(agg), nil
}

// WorkloadHealthStatus is the resolver for the workloadHealthStatus field.
func (r *k8sWorkloadResolver) WorkloadHealthStatus(ctx context.Context, obj *model.K8sWorkload) (*model.DesiredConditionStatus, error) {
	l := loaders.For(ctx)
	workload, err := l.GetWorkloadManifest(ctx, *obj.ID)
	if err != nil {
		return nil, err
	}

	if workload == nil {
		return nil, nil
	}

	// WorkloadHealthStatus may also be nil here which is ok
	return workload.WorkloadHealthStatus, nil
}

// ProcessesHealthStatus is the resolver for the processesHealthStatus field.
func (r *k8sWorkloadResolver) ProcessesHealthStatus(ctx context.Context, obj *model.K8sWorkload) (*model.DesiredConditionStatus, error) {
	l := loaders.For(ctx)
	ic, err := l.GetInstrumentationConfig(ctx, *obj.ID)
	if err != nil {
		return nil, err
	}
	containerNamesWithOptionalPodManifestInjection := getContainerNamesWithOptionalPodManifestInjection(ic)
	return aggregateProcessesHealthForWorkload(ctx, obj.ID, containerNamesWithOptionalPodManifestInjection)
}

// TelemetryMetrics is the resolver for the telemetryMetrics field.
func (r *k8sWorkloadResolver) TelemetryMetrics(ctx context.Context, obj *model.K8sWorkload) ([]*model.K8sWorkloadTelemetryMetrics, error) {
	var totalDataSent *int
	var throughput *int

	// attempt to get the metrics for the workload, or keep them as nil if not available.
	workloadMetrics, ok := r.MetricsConsumer.GetSingleSourceMetrics(frontendcommon.SourceID{
		Namespace: obj.ID.Namespace,
		Kind:      k8sconsts.WorkloadKind(obj.ID.Kind),
		Name:      obj.ID.Name,
	})
	if ok {
		tds := int(workloadMetrics.TotalDataSent())
		tp := int(workloadMetrics.TotalThroughput())
		totalDataSent = &tds
		throughput = &tp
	}

	return []*model.K8sWorkloadTelemetryMetrics{
		{
			TotalDataSentBytes: totalDataSent,
			ThroughputBytes:    throughput,
		},
	}, nil
}

// DataStreamNames is the resolver for the dataStreamNames field.
func (r *k8sWorkloadResolver) DataStreamNames(ctx context.Context, obj *model.K8sWorkload) ([]string, error) {
	if obj.DataStreamNames != nil {
		return obj.DataStreamNames, nil
	}
	l := loaders.For(ctx)
	sources, err := l.GetSources(ctx, *obj.ID)
	if err != nil {
		return []string{}, err
	}

	ptrNames := services.ExtractDataStreamsFromSource(sources.Workload, sources.Namespace)
	names := make([]string, len(ptrNames))
	for i, p := range ptrNames {
		names[i] = *p
	}
	return names, nil
}

// NumberOfInstances is the resolver for the numberOfInstances field.
func (r *k8sWorkloadResolver) NumberOfInstances(ctx context.Context, obj *model.K8sWorkload) (*int, error) {
	if obj.NumberOfInstances != nil {
		return obj.NumberOfInstances, nil
	}
	l := loaders.For(ctx)
	workloadManifest, err := l.GetWorkloadManifest(ctx, *obj.ID)
	if err != nil {
		return nil, err
	}
	if workloadManifest == nil {
		return nil, nil
	}
	count := int(workloadManifest.AvailableReplicas)
	return &count, nil
}

// RollbackOccurred is the resolver for the rollbackOccurred field.
func (r *k8sWorkloadResolver) RollbackOccurred(ctx context.Context, obj *model.K8sWorkload) (bool, error) {
	l := loaders.For(ctx)
	ic, err := l.GetInstrumentationConfig(ctx, *obj.ID)
	if err != nil {
		return false, err
	}
	if ic == nil {
		return false, nil
	}
	return ic.Status.RollbackOccurred, nil
}

// Processes is the resolver for the processes field.
func (r *k8sWorkloadPodContainerResolver) Processes(ctx context.Context, obj *model.K8sWorkloadPodContainer) ([]*model.K8sWorkloadPodContainerProcess, error) {
	l := loaders.For(ctx)

	containerName := obj.ContainerName

	// extract pod info from the parent resolver context
	fc := graphql.GetFieldContext(ctx)
	if fc == nil || fc.Parent == nil || fc.Parent.Parent == nil || fc.Parent.Parent.Parent == nil {
		return nil, fmt.Errorf("missisng parent resolver context")
	}
	workloadPodCtx := fc.Parent.Parent.Parent
	p, ok := workloadPodCtx.Result.(**model.K8sWorkloadPod)
	if !ok || p == nil || (*p).PodName == "" {
		return nil, fmt.Errorf("parent is not a pod")
	}
	podName := (*p).PodName

	if workloadPodCtx.Parent == nil || workloadPodCtx.Parent.Parent == nil {
		return nil, fmt.Errorf("missing parent resolver context")
	}
	workloadCtx := workloadPodCtx.Parent.Parent
	c, ok := workloadCtx.Result.(**model.K8sWorkload)
	if !ok || c == nil || (*c).ID == nil {
		return nil, fmt.Errorf("parent is not a workload")
	}
	workloadId := *(*c).ID

	instrumentationInstances, err := l.GetInstrumentationInstancesForContainer(ctx, loaders.PodContainerId{
		Namespace:     workloadId.Namespace,
		PodName:       podName,
		ContainerName: containerName,
	})
	if err != nil {
		return nil, err
	}

	processes := make([]*model.K8sWorkloadPodContainerProcess, 0, len(instrumentationInstances))
	for _, instrumentationInstance := range instrumentationInstances {
		processHealthStatus := status.CalculateProcessHealthStatus(instrumentationInstance)

		identifyingAttributes := make([]*model.K8sWorkloadPodContainerProcessAttribute, 0, len(instrumentationInstance.Status.IdentifyingAttributes))
		for _, attribute := range instrumentationInstance.Status.IdentifyingAttributes {
			identifyingAttributes = append(identifyingAttributes, &model.K8sWorkloadPodContainerProcessAttribute{
				Name:  attribute.Key,
				Value: attribute.Value,
			})
		}
		slices.SortFunc(identifyingAttributes, func(a, b *model.K8sWorkloadPodContainerProcessAttribute) int {
			return cmp.Compare(a.Name, b.Name)
		})

		instrumentations := make([]*model.K8sWorkloadPodContainerProcessInstrumentation, 0, len(instrumentationInstance.Status.Components))
		for _, component := range instrumentationInstance.Status.Components {
			if component.Type != odigosv1.InstrumentationLibraryTypeInstrumentation {
				continue
			}
			instrumentations = append(instrumentations, componentToInstrumentation(component))
		}
		slices.SortFunc(instrumentations, func(a, b *model.K8sWorkloadPodContainerProcessInstrumentation) int {
			return cmp.Compare(a.Name, b.Name)
		})

		processes = append(processes, &model.K8sWorkloadPodContainerProcess{
			Healthy:               instrumentationInstance.Status.Healthy,
			HealthStatus:          processHealthStatus,
			IdentifyingAttributes: identifyingAttributes,
			Instrumentations:      instrumentations,
		})
	}
	slices.SortFunc(processes, func(a, b *model.K8sWorkloadPodContainerProcess) int {
		return compareProcessesByPid(a, b)
	})
	return processes, nil
}

// PodsManifestInjectionOverview is the resolver for the podsManifestInjectionOverview field.
func (r *k8sWorkloadRolloutResolver) PodsManifestInjectionOverview(ctx context.Context, obj *model.K8sWorkloadRollout) (*model.K8sWorkloadPodsManifestInjectionOverview, error) {
	if obj != nil && obj.PodsManifestInjectionOverview != nil {
		return obj.PodsManifestInjectionOverview, nil
	}

	fc := graphql.GetFieldContext(ctx)
	// current field -> *model.K8sWorkloadRollout -> *model.K8sWorkload
	if fc == nil || fc.Parent == nil || fc.Parent.Parent == nil {
		return nil, fmt.Errorf("missing parent resolver context")
	}
	w, ok := fc.Parent.Parent.Result.(**model.K8sWorkload)
	if !ok || w == nil || (*w).ID == nil {
		return nil, fmt.Errorf("parent is not a workload")
	}
	workloadId := *(*w).ID

	l := loaders.For(ctx)
	pods, err := l.GetWorkloadPods(ctx, workloadId)
	if err != nil {
		return nil, err
	}
	ic, err := l.GetInstrumentationConfig(ctx, workloadId)
	if err != nil {
		return nil, err
	}

	return status.CalculatePodsManifestInjectionOverview(ic, pods), nil
}

// ExpectingTelemetry is the resolver for the expectingTelemetry field.
func (r *k8sWorkloadTelemetryMetricsResolver) ExpectingTelemetry(ctx context.Context, obj *model.K8sWorkloadTelemetryMetrics) (*model.K8sWorkloadTelemetryMetricsExpectingTelemetryStatus, error) {
	// Safely derive the parent workload ID from the GraphQL field context
	var workloadId model.K8sWorkloadID
	fc := graphql.GetFieldContext(ctx)
	// go up 3 levels in the context to get the workload id
	// current field -> *model.K8sWorkloadTelemetryMetrics -> []*model.K8sWorkloadTelemetryMetrics -> *model.K8sWorkload
	if fc == nil || fc.Parent == nil || fc.Parent.Parent == nil || fc.Parent.Parent.Parent == nil {
		return nil, fmt.Errorf("missisng parent resolver context")
	}
	w, ok := fc.Parent.Parent.Parent.Result.(**model.K8sWorkload)
	if !ok || w == nil || (*w).ID == nil {
		return nil, fmt.Errorf("parent is not a workload")
	}
	workloadId = *(*w).ID

	l := loaders.For(ctx)
	pods, err := l.GetWorkloadPods(ctx, workloadId)
	if err != nil {
		return nil, err
	}
	ic, err := l.GetInstrumentationConfig(ctx, workloadId)
	if err != nil {
		return nil, err
	}

	return status.CalculateExpectingTelemetryStatus(ic, pods, obj.TotalDataSentBytes), nil
}

// Workloads is the resolver for the workloads field.
// Pre-computes all field values sequentially to avoid gqlgen spawning O(N × fields)
// goroutines for concurrent field resolution. At 10K workloads × 17 resolver fields,
// that would be 170K goroutines (~430MB of stack memory), exceeding the pod limit.
// Uses heavyWorkloadQueryMu to prevent concurrent queries from doubling memory.
func (r *queryResolver) Workloads(ctx context.Context, filter *model.WorkloadFilter) ([]*model.K8sWorkload, error) {
	heavyWorkloadQueryMu.Lock()
	defer heavyWorkloadQueryMu.Unlock()

	l := loaders.For(ctx)
	if err := l.LoadWorkloadsWithFilter(ctx, filter); err != nil {
		return nil, err
	}

	workloadIds := l.GetWorkloadIds()
	results := make([]*model.K8sWorkload, 0, len(workloadIds))

	// Resolved once per request and threaded through populateWorkloadFields so
	// tier-gated checks (e.g. static-pod enterprise gating) don't re-fetch
	// the deployment ConfigMap per workload in large clusters.
	tier := services.GetTier(ctx)

	for _, id := range workloadIds {
		w := &model.K8sWorkload{ID: &id}
		r.populateWorkloadFields(ctx, l, w, tier)
		results = append(results, w)
	}

	return results, nil
}

// WorkloadsByIds is the resolver for the workloadsByIds field.
func (r *queryResolver) WorkloadsByIds(ctx context.Context, ids []*model.K8sWorkloadIDInput) ([]*model.K8sWorkload, error) {
	l := loaders.For(ctx)

	workloadIds := make([]model.K8sWorkloadID, 0, len(ids))
	for _, id := range ids {
		workloadIds = append(workloadIds, model.K8sWorkloadID{
			Namespace: id.Namespace,
			Kind:      id.Kind,
			Name:      id.Name,
		})
	}

	if err := l.SetWorkloadIdsDirect(ctx, workloadIds); err != nil {
		return nil, err
	}

	result := make([]*model.K8sWorkload, 0, len(workloadIds))
	for _, id := range l.GetWorkloadIds() {
		id := id
		result = append(result, &model.K8sWorkload{ID: &id})
	}
	return result, nil
}

// Namespaces is the resolver for the namespaces field.
// Only loads config + namespace list. Workload data is deferred to the
// K8sNamespace.Workloads field resolver, so queries that don't request
// workloads avoid the heavy manifest/source loading entirely.
func (r *queryResolver) Namespaces(ctx context.Context) ([]*model.K8sNamespace, error) {
	l := loaders.For(ctx)
	if err := l.LoadConfig(ctx); err != nil {
		return nil, err
	}

	nss, err := l.GetNamespaces(ctx)
	if err != nil {
		return nil, err
	}

	gqlNss := make([]*model.K8sNamespace, 0, len(nss))
	for _, nsName := range nss {
		gqlNss = append(gqlNss, &model.K8sNamespace{
			Name: nsName,
		})
	}
	return gqlNss, nil
}

